import { GoogleLogin } from "@react-oauth/google";
import { jwtDecode } from "jwt-decode";
import React, { useState, useContext } from "react";
import { Link, useNavigate } from "react-router-dom";
import { AuthContext } from "../context/AuthContext";

const Login = () => {
  const [activeTab, setActiveTab] = useState("login");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [name, setName] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const navigate = useNavigate();

  const { login } = useContext(AuthContext);

  const handleLogin = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    if (!email || !password) {
      setError('Vui lòng nhập đầy đủ thông tin');
      setLoading(false);
      return;
    }

    try {
      const result = await login(email, password);
      if (result?.success) navigate('/');
      else setError(result?.message || 'Đăng nhập thất bại. Vui lòng kiểm tra email và mật khẩu.');
    } catch {
      setError('Có lỗi xảy ra khi đăng nhập. Vui lòng thử lại.');
    }
    setLoading(false);
  };

  const handleRegister = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    if (!name || !email || !password) {
      setError('Vui lòng nhập đầy đủ họ tên, email và mật khẩu');
      setLoading(false);
      return;
    }

    try {
      const result = await register(name, email, password, '', '', subscribeNewsletter);
      if (result?.success) navigate('/');
      else setError(result?.message || 'Đăng ký thất bại. Vui lòng thử lại.');
    } catch {
      setError('Có lỗi xảy ra khi đăng ký. Vui lòng thử lại.');
    }
    setLoading(false);
  };
  

  return (
    <div className="min-h-screen flex items-center justify-center bg-[#faf8f6] px-4 py-10">
      <div className="w-full max-w-md bg-white shadow-lg rounded-2xl border border-[#f2e4e0] p-8">
        <h2 className="text-center text-2xl font-semibold text-[#e06c7f] mb-6">
          {activeTab === 'login' ? '🌸 Đăng nhập' : '🌷 Đăng ký'}
        </h2>

        {/* Tabs */}
        <div className="flex mb-6 border-b border-[#f3e6e1]">
          <button
            className={`flex-1 py-2 font-medium transition ${
              activeTab === 'login'
                ? 'text-[#e06c7f] border-b-2 border-[#e06c7f]'
                : 'text-gray-500 hover:text-[#e06c7f]'
            }`}
            onClick={() => {
              setActiveTab('login');
              setError('');
            }}
          >
            Đăng nhập
          </button>
          <button
            className={`flex-1 py-2 font-medium transition ${
              activeTab === 'register'
                ? 'text-[#e06c7f] border-b-2 border-[#e06c7f]'
                : 'text-gray-500 hover:text-[#e06c7f]'
            }`}
            onClick={() => {
              setActiveTab('register');
              setError('');
            }}
          >
            Đăng ký
          </button>
        </div>

        {/* Thông báo lỗi */}
        {error && (
          <div className="bg-red-100 text-red-700 p-3 rounded-lg mb-4 border border-red-200 text-sm text-center">
            ⚠️ {error}
          </div>
        )}

        {/* Form Đăng nhập */}
        {activeTab === 'login' ? (
          <form onSubmit={handleLogin}>
            <input
              type="email"
              placeholder="Email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="w-full mb-3 p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#e06c7f] focus:border-transparent"
              disabled={loading}
            />

            <div className="relative mb-6">
              <input
                type={showPassword ? 'text' : 'password'}
                placeholder="Mật khẩu"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full p-3 pr-10 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#e06c7f]"
                disabled={loading}
              />
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                className="absolute right-3 top-3 text-gray-500 hover:text-[#e06c7f]"
              >
                {showPassword ? '🙈' : '👁️'}
              </button>
            </div>
             {/* 🔘 Nút đăng nhập chính */}
    <button
      type="submit"
      disabled={loading}
      className="w-full bg-[#e06c7f] text-white py-3 rounded-lg font-medium hover:bg-[#d35c70] transition mb-4"
    >
      {loading ? 'Đang đăng nhập...' : 'Đăng nhập'}
    </button>

    {/* Divider
    <div className="flex items-center my-4">
      <div className="flex-grow h-px bg-gray-300"></div>
      <div className="flex-grow h-px bg-gray-300"></div>
    </div> */}
{/* Divider */}
<div className="flex items-center my-4">
  <div className="flex-grow h-px bg-gray-300"></div>
  <span className="px-3 text-gray-500 text-sm">hoặc</span>
  <div className="flex-grow h-px bg-gray-300"></div>
</div>
<div className="flex justify-center mt-4">
  <GoogleLogin
  onSuccess={async (credentialResponse) => {
    const token = credentialResponse.credential;
    const decoded = jwtDecode(token);
    console.log("✅ Google login success:", decoded);

    try {
      const response = await fetch("http://localhost:5000/api/auth/google", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          email: decoded.email,
          name: decoded.name,
          googleId: decoded.sub,
          
        }),
      });

      const data = await response.json();

      if (data.success) {
        localStorage.setItem("user", JSON.stringify(data.user));
        localStorage.setItem("token", data.token);

        // 🟢 Nếu là admin thì vào dashboard
        if (data.user.role === "admin") {
          navigate("/admin");
        } else {
          navigate("/");
        }
      } else {
        setError("Không thể đăng nhập bằng Google.");
      }
    } catch (error) {
      console.error(error);
      setError("Lỗi máy chủ, vui lòng thử lại sau.");
    }
  }}
  onError={() => {
    console.error("❌ Google login failed");
    setError("Đăng nhập Google thất bại. Vui lòng thử lại!");
  }}
/>

</div>


            <div className="text-center mt-4">
              <Link to="/forgot-password" className="text-sm text-[#e06c7f] hover:underline">
                🔐 Quên mật khẩu?
              </Link>
            </div>
          </form>
        ) : (
          // Form Đăng ký
          <form onSubmit={handleRegister}>
            <input
              type="text"
              placeholder="Họ tên"
              value={name}
              onChange={(e) => setName(e.target.value)}
              className="w-full mb-3 p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#e06c7f]"
              disabled={loading}
            />
            <input
              type="email"
              placeholder="Email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="w-full mb-3 p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#e06c7f]"
              disabled={loading}
            />

            <div className="relative mb-4">
              <input
                type={showRegPassword ? 'text' : 'password'}
                placeholder="Mật khẩu"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full p-3 pr-10 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#e06c7f]"
                disabled={loading}
              />
              <button
                type="button"
                onClick={() => setShowRegPassword(!showRegPassword)}
                className="absolute right-3 top-3 text-gray-500 hover:text-[#e06c7f]"
              >
                {showRegPassword ? '🙈' : '👁️'}
              </button>
            </div>

            <label className="flex items-center mb-5 text-sm text-gray-700">
              <input
                type="checkbox"
                checked={subscribeNewsletter}
                onChange={(e) => setSubscribeNewsletter(e.target.checked)}
                className="mr-2 accent-[#e06c7f]"
              />
              📧 Nhận tin khuyến mãi & ưu đãi
            </label>

            <button
              type="submit"
              disabled={loading}
              className="w-full bg-[#e06c7f] text-white py-3 rounded-lg font-medium hover:bg-[#d35c70] transition"
            >
              {loading ? 'Đang đăng ký...' : 'Đăng ký tài khoản'}
            </button>

            <p className="text-xs text-gray-600 mt-3 text-center">
              Bằng cách đăng ký, bạn đồng ý với{' '}
              <Link to="/terms" className="text-[#e06c7f] hover:underline">
                Điều khoản
              </Link>{' '}
              &{' '}
              <Link to="/privacy" className="text-[#e06c7f] hover:underline">
                Chính sách bảo mật
              </Link>.
            </p>
          </form>
        )}
      </div>
    </div>
  );
};

export default Login;
